            const waterEndFirst = waterStartTime[j] + waterDuration[j];
            const landStart = Math.max(landStartTime[i], waterEndFirst);
            const landEndSecond = landStart + landDuration[i];
            const case2 = landEndSecond;

            const currentMin = Math.min(case1, case2);
            if (currentMin < minTime) {
                minTime = currentMin;
            }
        }
    }
    return minTime;
}
